]

instance WindSpeedTimeseries : DTDFVocab:Data [
    base:desc "Time‑series of wind speed readings stored in TimescaleDB"
    DTDFVocab:fromData WindSpeedTelemetry
    DTDFVocab:inputTo TimescaleDBStorage, MqttBroker
]

instance MotorStatusTimeseries : DTDFVocab:Data [
    base:desc "Time‑series of motor encoder data stored in TimescaleDB"
    DTDFVocab:fromData MotorStatusTelemetry
    DTDFVocab:inputTo TimescaleDBStorage, MqttBroker
]

instance AggregatedTimeseries : DTDFVocab:Data [
    base:desc "Aggregated telemetry time‑series stored in TimescaleDB"
    DTDFVocab:fromData AggregatedTelemetry
    DTDFVocab:inputTo TimescaleDBStorage, MqttBroker
]

